// Summary: Tests ImagePanel structure, token classes, media attributes, label accessibility, and action slot rendering.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { ImagePanel, type ImagePanelProps } from './ImagePanel';

let consoleErrorSpy: jest.SpyInstance;

beforeAll(() => {
  consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation(() => {});
});

afterAll(() => {
  consoleErrorSpy?.mockRestore();
});

const baseProps: ImagePanelProps = {
  imgSrc: 'https://example.com/image.jpg',
  imgAlt: 'Sunrise over mountains',
  title: 'Explore the alpine trail',
  description: 'Discover guided tours, local tips, and seasonal highlights.',
  labels: [{ label: 'Guided' }],
  actions: [<button type="button">Start planning</button>]
};

const renderImagePanel = (props?: Partial<ImagePanelProps>) => {
  return render(<ImagePanel {...baseProps} {...props} />);
};

describe('ImagePanel', () => {
  it('renders image, overlay, and content slots followed by title, description, labels, and actions', () => {
    const { container } = renderImagePanel();
    const base = container.querySelector('[data-slot="base"]');
    const slotOrder = Array.from(base?.children ?? []).map(child =>
      child.getAttribute('data-slot')
    );
    const content = base?.querySelector('[data-slot="_content"]');
    const contentOrder = Array.from(content?.children ?? []).map(child =>
      child.getAttribute('data-slot')
    );
    const matchesOrder =
      JSON.stringify(slotOrder) === JSON.stringify(['_image', '_overlay', '_content']) &&
      JSON.stringify(contentOrder) ===
        JSON.stringify(['_actions', '_title', '_description', '_labels']);
    expect(matchesOrder).toBe(true);
  });

  it('applies hero sizing and transition token classes to the base and content slots', () => {
    const { container } = renderImagePanel();
    const base = container.querySelector('[data-slot="base"]');
    const content = container.querySelector('[data-slot="_content"]');
    const tokensApplied =
      (base?.className.includes('w-97.5') ?? false) &&
      (base?.className.includes('group-data-[is-in-view=true]:scale-100') ?? false) &&
      (content?.className.includes('opacity-0') ?? false) &&
      (content?.className.includes('group-data-[is-in-view=true]:opacity-100') ?? false);
    expect(tokensApplied).toBe(true);
  });

  it('passes source, alt, default loading, and omits fetchpriority attribute when not provided', () => {
    const { container } = renderImagePanel();
    const image = container.querySelector('[data-slot="_image"]') as HTMLImageElement | null;
    const mediaPropsApplied =
      Boolean(image) &&
      image?.getAttribute('src') === baseProps.imgSrc &&
      image?.getAttribute('alt') === baseProps.imgAlt &&
      image?.getAttribute('loading') === 'lazy' &&
      image?.hasAttribute('fetchpriority') === false;
    expect(mediaPropsApplied).toBe(true);
  });

  it('supports fetchpriority when provided', () => {
    const { container } = renderImagePanel({ fetchPriority: 'high' });
    const image = container.querySelector('[data-slot="_image"]') as HTMLImageElement | null;
    const fetchPriorityApplied = Boolean(image) && image?.getAttribute('fetchpriority') === 'high';
    expect(fetchPriorityApplied).toBe(true);
  });

  it('renders labels with optional icons hidden and aria-label applied when provided', () => {
    renderImagePanel({
      labels: [
        { label: 'Outdoors', icon: <span>🗻</span> },
        { label: 'Guided', ariaLabel: 'Guided experiences available' }
      ]
    });
    const labelItems = screen.getAllByText(/Outdoors|Guided/);
    const iconWrapper = document.querySelector('[data-slot="_labelIcon"]');
    const accessibilityApplied =
      labelItems.length === 2 &&
      iconWrapper?.getAttribute('aria-hidden') === 'true' &&
      document.querySelectorAll('[data-slot="_labelItem"]')[1]?.getAttribute('aria-label') ===
        'Guided experiences available';
    expect(accessibilityApplied).toBe(true);
  });

  it('renders provided action nodes as direct children of the actions slot', () => {
    const { container } = renderImagePanel({
      actions: [
        <button type="button">Book now</button>,
        <a href="https://example.com">Learn more</a>
      ]
    });
    const actionsSlot = container.querySelector('[data-slot="_actions"]');
    const button = screen.getByRole('button', { name: 'Book now' });
    const link = screen.getByRole('link', { name: 'Learn more' });
    const actionsApplied =
      Boolean(actionsSlot?.contains(button)) &&
      Boolean(actionsSlot?.contains(link)) &&
      (actionsSlot?.childElementCount ?? 0) === 2;
    expect(actionsApplied).toBe(true);
  });

  it('omits title and description slots when not provided while keeping actions and labels', () => {
    const { container } = renderImagePanel({ title: undefined, description: undefined });
    const actionsSlot = container.querySelector('[data-slot="_actions"]');
    const labelsSlot = container.querySelector('[data-slot="_labels"]');
    const titleSlot = container.querySelector('[data-slot="_title"]');
    const descriptionSlot = container.querySelector('[data-slot="_description"]');
    const remainsValid =
      Boolean(actionsSlot) && Boolean(labelsSlot) && titleSlot === null && descriptionSlot === null;
    expect(remainsValid).toBe(true);
  });

  it('normalizes non-array labels and actions to empty collections without throwing', () => {
    const { container } = renderImagePanel({
      labels: 'invalid' as unknown as ImagePanelProps['labels'],
      actions: 'invalid' as unknown as ImagePanelProps['actions']
    });
    const labelsSlot = container.querySelector('[data-slot="_labels"]');
    const labelItems = container.querySelectorAll('[data-slot="_labelItem"]');
    const actionsSlot = container.querySelector('[data-slot="_actions"]');
    const actionChildren = actionsSlot?.children.length ?? 0;
    const normalized =
      Boolean(labelsSlot) &&
      labelItems.length === 0 &&
      Boolean(actionsSlot) &&
      actionChildren === 0;
    expect(normalized).toBe(true);
  });

  it('falls back to empty labels and actions when props are omitted', () => {
    const { container } = render(
      <ImagePanel
        imgSrc={baseProps.imgSrc}
        imgAlt={baseProps.imgAlt}
        loading={baseProps.loading}
        title={baseProps.title}
        description={baseProps.description}
      />
    );
    const labelsSlot = container.querySelector('[data-slot="_labels"]');
    const actionsSlot = container.querySelector('[data-slot="_actions"]');
    const hasDefaults =
      Boolean(labelsSlot) &&
      labelsSlot?.children.length === 0 &&
      Boolean(actionsSlot) &&
      actionsSlot?.children.length === 0;
    expect(hasDefaults).toBe(true);
  });
});
